# 여러 숫자의 평균을 구하는 함수
def average(*numbers):
    if len(numbers) == 0:
        return 0
    return sum(numbers) / len(numbers)

print(average(1, 2, 3))     # 2.0
print(average(10, 20, 30, 40))  # 25.0

# 사용자 정보를 출력하는 함수
def print_info(**kwargs):
    for key, value in kwargs.items():
        print(f'{key}: {value}')

print_info(이름='이파이', 나이=25, 도시='서울')

class Dog:
    def __init__(self, name, age):
        self.name = name  # 이름 속성
        self.age = age    # 나이 속성

    def bark(self):
        print(f'{self.name}: 왈왈!')

    def info(self):
        print(f'이름: {self.name}, 나이: {self.age}살')

# 객체(인스턴스) 생성
dog1 = Dog('바둑이', 3)
dog2 = Dog('콩이', 1)

dog1.bark()
dog2.info()
